import socket
import struct
import json
import time
import hashlib
import hmac
import os
from collections import defaultdict
from threading import Lock

# Configuration
SERVER_HOST = "0.0.0.0"
SERVER_PORT = 27015
MAX_PLAYERS = 64
SERVER_NAME = "My Game Server"
MAP_NAME = "de_dust2"
GAME_MODE = "competitive"

# Anti-amplification and rate limiting configuration
MAX_RESPONSE_SIZE = 1400  # Keep responses under typical MTU to avoid fragmentation
RATE_LIMIT_WINDOW = 10  # seconds
RATE_LIMIT_MAX_REQUESTS = 10  # max requests per IP per window
CHALLENGE_EXPIRY = 30  # seconds
MAX_TRACKED_IPS = 100000

# Protocol constants
QUERY_TYPE_STATUS = 0x01
QUERY_TYPE_PLAYERS = 0x02
QUERY_TYPE_CHALLENGE = 0x03
QUERY_TYPE_STATUS_RESPONSE = 0x81
QUERY_TYPE_PLAYERS_RESPONSE = 0x82
QUERY_TYPE_CHALLENGE_RESPONSE = 0x83
QUERY_TYPE_RATE_LIMITED = 0xFE
QUERY_TYPE_CHALLENGE_REQUIRED = 0xFF


class RateLimiter:
    """Per-IP rate limiter to prevent abuse."""

    def __init__(self, window_seconds, max_requests, max_tracked_ips):
        self.window = window_seconds
        self.max_requests = max_requests
        self.max_tracked_ips = max_tracked_ips
        self.requests = defaultdict(list)
        self.lock = Lock()

    def is_allowed(self, ip):
        now = time.monotonic()
        with self.lock:
            # Periodic cleanup to prevent memory exhaustion
            if len(self.requests) > self.max_tracked_ips:
                self._cleanup(now)

            # Remove old entries for this IP
            self.requests[ip] = [
                t for t in self.requests[ip] if now - t < self.window
            ]

            if len(self.requests[ip]) >= self.max_requests:
                return False

            self.requests[ip].append(now)
            return True

    def _cleanup(self, now):
        expired_ips = [
            ip for ip, times in self.requests.items()
            if not times or now - times[-1] >= self.window
        ]
        for ip in expired_ips:
            del self.requests[ip]


class ChallengeManager:
    """Challenge-response system to verify client IP addresses and prevent spoofing."""

    def __init__(self, expiry_seconds, max_tracked):
        self.expiry = expiry_seconds
        self.max_tracked = max_tracked
        self.challenges = {}
        self.lock = Lock()
        # Secret key for HMAC-based challenge generation (not stored per-client)
        self.secret = os.urandom(32)

    def generate_challenge(self, addr):
        """Generate a challenge token for an address."""
        now = time.monotonic()
        # Use HMAC so we can verify without storing state per-client
        addr_bytes = f"{addr[0]}:{addr[1]}:{int(now // self.expiry)}".encode()
        challenge = hmac.new(self.secret, addr_bytes, hashlib.sha256).digest()[:8]
        challenge_int = struct.unpack("!Q", challenge)[0]

        with self.lock:
            # Also store it for explicit verification with timestamp
            if len(self.challenges) > self.max_tracked:
                self._cleanup(now)
            self.challenges[addr] = (challenge_int, now)

        return challenge_int

    def verify_challenge(self, addr, challenge_value):
        """Verify a challenge response from a client."""
        now = time.monotonic()

        # Check current and previous time windows (to handle boundary cases)
        for offset in [0, -1]:
            window = int(now // self.expiry) + offset
            addr_bytes = f"{addr[0]}:{addr[1]}:{window}".encode()
            expected = hmac.new(self.secret, addr_bytes, hashlib.sha256).digest()[:8]
            expected_int = struct.unpack("!Q", expected)[0]
            if hmac.compare_digest(
                struct.pack("!Q", challenge_value),
                struct.pack("!Q", expected_int)
            ):
                return True

        # Also check stored challenge as fallback
        with self.lock:
            if addr in self.challenges:
                stored_challenge, timestamp = self.challenges[addr]
                if now - timestamp < self.expiry and hmac.compare_digest(
                    struct.pack("!Q", challenge_value),
                    struct.pack("!Q", stored_challenge)
                ):
                    del self.challenges[addr]
                    return True

        return False

    def _cleanup(self, now):
        expired = [
            addr for addr, (_, ts) in self.challenges.items()
            if now - ts >= self.expiry
        ]
        for addr in expired:
            del self.challenges[addr]


class GameState:
    """Simulated game state."""

    def __init__(self):
        self.players = []
        self.server_name = SERVER_NAME
        self.map_name = MAP_NAME
        self.game_mode = GAME_MODE
        self.max_players = MAX_PLAYERS
